import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        int maxIndex = n - 1;
        boolean[] sieve = new boolean[maxIndex + 1];
        Arrays.fill(sieve, true);
        sieve[0] = sieve[1] = false;
        for (int i = 2; i * i <= maxIndex; i++) {
            if (sieve[i]) {
                for (int j = i * i; j <= maxIndex; j += i) {
                    sieve[j] = false;
                }
            }
        }
        long sumA = 0;
        long sumB = 0;
        for (int i = 0; i < n; i++) {
            if (sieve[i]) {
                sumA += nums[i];
            } else {
                sumB += nums[i];
            }
        }
        return Math.abs(sumA - sumB);
    }
}
